INSERT INTO `hospitals` VALUES (5,3,'Çermik Devlet Hastanesi','',38.14398663,39.47550299,'','','2026-03-11 08:51:00',NULL,NULL),(6,5,'Çüngüş İlçe Devlet Hastanesi','Diyarbakır’ın Çüngüş Devlet Hastanesi, ilçenin coğrafi yapısı ve ulaşım şartları göz önüne alındığında kritik bir öneme sahip olan, butik ama modern bir sağlık kuruluşudur. 2026 yılı itibarıyla güncel bilgiler şöyledir:\r\n\r\n🏥 Genel Kapasite ve Bina Özellikleri\r\nYatak Kapasitesi: 10 yataklı bir ilçe hastanesidir (Entegre sağlık hizmeti sunar).\r\n\r\nModernizasyon: Hastane, deprem güvenliği ve modern sağlık standartlarına uygun olarak yenilenmiş bir binada hizmet vermektedir.\r\n\r\nHizmet Yapısı: \"E-Grubu\" entegre ilçe hastanesi kategorisindedir;

