INSERT INTO `settings` VALUES (1,0,'mayor_name','Suat AKMEŞE','2026-03-11 20:36:26','FREEMIND','7073c30918869aee144ddca9','bb37df2be980e603326bce12'),(2,0,'mayor_title','Çüngüş Belediye Başkanı','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(3,0,'mayor_image','assets/img/baskan.png','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(4,0,'site_name','Çermik Belediyesi','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(5,0,'site_email','admin@cermil.bel.tr','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(6,0,'site_phone','4124612001','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(7,0,'site_address','Tepe Mah.','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(8,0,'copyright_text','Rotamız Çermik','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(9,0,'facebook_link','https://www.facebook.com/p/%C3%87ermik-Belediyesi-100064935810446/?locale=tr_TR','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(10,0,'instagram_link','https://www.instagram.com/cermikbelediyesi/','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(11,0,'youtube_link','https://www.youtube.com/@cermikbelediyesi','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(12,0,'twitter_link','https://x.com/cermikbld/status/1923747974338748880','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(13,0,'kvkk_text','1. İşlenen Kişisel Verileriniz\r\nUygulamayı kullanımınız sırasında aşağıdaki verileriniz işlenebilir:\r\n\r\nKimlik Bilgileri: Ad, soyadı.\r\n\r\nİletişim Bilgileri: E-posta adresi, telefon numarası.\r\n\r\nKonum Bilgileri: Cihazınızın GPS verileri (yakınındaki tarihi yerleri göstermek ve bildirim göndermek amacıyla).\r\n\r\nİşlem Güvenliği: IP adresi, uygulama giriş-ğıkış kayıtları, cihaz modeli.\r\n\r\n2. Kişisel Verilerin İşlenme Amağları\r\nKişisel verileriniz, çermikÔÇÖin tanıtımı ve belediye hizmetlerinin iyileştirilmesi amacıyla şu durumlarda işlenir:\r\n\r\nUygulama iğerisinde kullanıcı hesabı oluşturulması.\r\n\r\nYerel Rehber hizmeti kapsamında konumunuza yakın tarihi ve turistik yerlerin (├ûrn: Hanbaşı Camii, Karakaya Hanı) gösterilmesi.\r\n\r\nBelediye duyuruları, etkinlikler ve turistik bilgilendirmeler hakkında bildirim gönderilmesi.\r\n\r\nUygulama performansının ölğülmesi ve kullanıcı deneyiminin geliştirilmesi.\r\n\r\n3. Kişisel Verilerin Aktarılması\r\nKişisel verileriniz, yasal yükümlülüklerin yerine getirilmesi amacıyla yetkili kamu kurum ve kuruluşları ile paylaşılabilecek olup;

